INSERT INTO `empresa_infos` VALUES (3,'Empresa CodeGO - Líder em desenvolvimento econômico.','/static/empresa1.jpg'),(4,'Empresa ABC - Soluções inovadoras.','/static/empresa2.jpg'),(295,'','/static/empresa295.jpg'),(392,NULL,'/static/imagens_empresas/empresa392.jpeg'),(395,'Há mais de 45 anos, a VITAMEDIC iniciou sua trajetória rumo ao sonho de transformar essa pequena empresa Goiana em referência nacional na produção e comercialização de medicamentos.\n\nBuscamos diariamente pela concretização desse sonho, trilhando o caminho de crescimento e consolidação da nossa marca no mercado. Por isso, em abril de 2015 passamos a pertencer ao Grupo José Alves e firmamos um recomeço rumo ao sucesso.','/static/empresa395.jpg'),(422,'Investindo sempre em aprimoramento tecnológico e apostando na extraordinária força de trabalho de sua equipe, o Teuto atravessa quase 8 décadas vencendo desafios e passando com sucesso por todas as dificuldades.\n\nAtualmente, a companhia possui mais de 540 produtos registrados entre medicamentos de referência, genéricos, genéricos de marca (similares equivalentes ÔÇô EQÔÇÖs), MIPÔÇÖs (medicamentos isentos de prescrição), linha de especialidades, que incluiu os biossimilares. Além disso, temos os suplementos alimentares, cosméticos e produtos para a saúde. Nos próximos anos, está programado o lançamento de mais de 250 novas apresentações.','/static/empresa422.jpeg'),(469,'','/static/empresa469.png'),(506,'A Granol é uma grande empresa brasileira do agronegócio, atuante no processamento de grãos, produção de óleo de soja, farelo, biodiesel, lecitina e glicerina, com unidades importantes no complexo industrial do DAIA em Anápolis (GO) e outras no Brasil, focando em qualidade, sustentabilidade e geração de valor para o agronegócio nacional, sendo uma das líderes no setor.','/static/empresa506.png'),(539,'Há mais de 45 anos, a VITAMEDIC iniciou sua trajetória rumo ao sonho de transformar essa pequena empresa Goiana em referência nacional na produção e comercialização de medicamentos.\n\nBuscamos diariamente pela concretização desse sonho, trilhando o caminho de crescimento e consolidação da nossa marca no mercado. Por isso, em abril de 2015 passamos a pertencer ao Grupo José Alves e firmamos um recomeço rumo ao sucesso.','/static/empresa539.jpg'),(548,'A Brainfarma Indústria Química e Farmacêutica S.A. é uma das maiores fabricantes de medicamentos do Brasil. Conta hoje com um dos mais modernos centros de pesquisa e desenvolvimento de produtos farmacêuticos no país.\n\nEm Anápolis, está localizada a fábrica de medicamentos, uma das maiores da América Latina, com cerca de 120 mil metros quadrados de áreas construída, que abriga mais de 4600 colaboradores.\n\nEssa unidade tem capacidade para produzir mais de 830 itens distintos, nas mais variadas formas farmacêuticas: sólidos, líquidos, semissólidos, efervescentes, injetáveis, aerossóis, dentre outras.','/static/empresa548.jpg'),(654,NULL,'/static/imagens_empresas/empresa654.webp'),(661,'','/static/empresa661.jpeg'),(925,'sadasdaccccc','imagens_empresas/empresa925.jpg'),(926,'otima churrascaria','/static/imagens_empresas/empresa926.jpg');
